#!/usr/bin/env node
// Content-hash-gated publishing for the TypeSpec-generated @remit/* packages.
//
// These packages live under build/ — regenerated by `make`, not npm workspaces,
// so changesets neither versions nor publishes them. This publishes them from
// the same Publish run, keyed to the public registry rather than git tags.
//
// Per package, each run: stamp the publish metadata (license, access,
// repository, required peer deps), build a deterministic content hash of the
// freshly generated package, and compare it against the content of the version
// currently on the registry. Identical -> skip. Different -> publish a patch
// bump over the registry's latest. Absent -> seed 0.0.1. The hash normalizes the
// version field and hashes file contents, so tarball timestamps and the version
// string never cause a spurious republish; a deterministic codegen output makes
// an unchanged run a guaranteed skip. Idempotent and safe on every run.
//
// Usage: publish-generated.mjs [--dry-run]
//   --dry-run  compute and print each decision, pack-check, never publish.
import { execFileSync } from "node:child_process";
import { createHash } from "node:crypto";
import { mkdtempSync, readdirSync, readFileSync, rmSync, statSync, writeFileSync } from "node:fs";
import { tmpdir } from "node:os";
import { dirname, join, relative } from "node:path";
import { fileURLToPath } from "node:url";

const repoRoot = join(dirname(fileURLToPath(import.meta.url)), "..");
const dryRun = process.argv.includes("--dry-run");

const repositoryUrl = "git+https://github.com/remit-mail/reader.git";

// The generated set. `peerDependencies` names the runtime libraries the built
// output imports but expects the consumer to supply — merged onto whatever the
// emitter already declared so a standalone install resolves them.
const generated = [
	{ dir: "build/ts-enums", name: "@remit/domain-enums", peerDependencies: {} },
	{ dir: "build/openapi-types", name: "@remit/api-openapi-types", peerDependencies: {} },
	{ dir: "build/zod-schemas", name: "@remit/api-zod-schemas", peerDependencies: { zod: "^3.0.0" } },
	{ dir: "build/ddb-entities", name: "@remit/electrodb-entities", peerDependencies: { electrodb: ">=3.0.0" } },
	{ dir: "build/remit-client", name: "@remit/api-http-client", peerDependencies: { "@tanstack/react-query": "^5.0.0" } },
	{ dir: "build/drizzle-entities", name: "@remit/drizzle-pg-schema", peerDependencies: {} },
	{ dir: "build/drizzle-entities-sqlite", name: "@remit/drizzle-sqlite-schema", peerDependencies: {} },
];

const run = (cmd, args, opts = {}) =>
	execFileSync(cmd, args, { encoding: "utf8", ...opts });

const walkFiles = (root) => {
	const out = [];
	const recurse = (current) => {
		for (const entry of readdirSync(current)) {
			const path = join(current, entry);
			if (statSync(path).isDirectory()) recurse(path);
			else out.push(path);
		}
	};
	recurse(root);
	return out;
};

// Hash of an extracted package directory: version normalized to a constant, then
// the sha256 of each file's bytes combined with its path, ordered by path. The
// same function runs over the freshly packed output and the downloaded registry
// tarball, so equal content yields equal hashes regardless of version or tar
// metadata.
const hashPackageDir = (packageDir) => {
	const manifestPath = join(packageDir, "package.json");
	const manifest = JSON.parse(readFileSync(manifestPath, "utf8"));
	manifest.version = "0.0.0";
	writeFileSync(manifestPath, JSON.stringify(manifest));

	const files = walkFiles(packageDir)
		.map((path) => relative(packageDir, path))
		.sort();
	const combined = createHash("sha256");
	for (const rel of files) {
		const fileHash = createHash("sha256")
			.update(readFileSync(join(packageDir, rel)))
			.digest("hex");
		combined.update(`${fileHash}\0${rel}\n`);
	}
	return combined.digest("hex");
};

const withTempDir = (fn) => {
	const dir = mkdtempSync(join(tmpdir(), "remit-pack-"));
	try {
		return fn(dir);
	} finally {
		rmSync(dir, { recursive: true, force: true });
	}
};

const extractedTarballDir = (tempDir) => {
	const tarball = readdirSync(tempDir).find((f) => f.endsWith(".tgz"));
	run("tar", ["-xzf", join(tempDir, tarball), "-C", tempDir]);
	return join(tempDir, "package");
};

const freshContentHash = (pkgDir) =>
	withTempDir((tempDir) => {
		run("npm", ["pack", "--pack-destination", tempDir, "--loglevel=error"], {
			cwd: join(repoRoot, pkgDir),
		});
		return hashPackageDir(extractedTarballDir(tempDir));
	});

const publishedContentHash = (name, version) =>
	withTempDir((tempDir) => {
		run("npm", ["pack", `${name}@${version}`, "--pack-destination", tempDir, "--loglevel=error"], {
			cwd: repoRoot,
		});
		return hashPackageDir(extractedTarballDir(tempDir));
	});

const registryLatest = (name) => {
	try {
		return run("npm", ["view", name, "version", "--loglevel=error"], {
			cwd: repoRoot,
			stdio: ["ignore", "pipe", "pipe"],
		}).trim();
	} catch (error) {
		const text = `${error.stdout ?? ""}${error.stderr ?? ""}`;
		if (text.includes("E404") || text.includes("404")) return null;
		throw error;
	}
};

const patchBump = (version) => {
	const [major, minor, patch] = version.split(".").map(Number);
	return `${major}.${minor}.${patch + 1}`;
};

const setVersion = (pkgDir, version) => {
	const manifestPath = join(repoRoot, pkgDir, "package.json");
	const manifest = JSON.parse(readFileSync(manifestPath, "utf8"));
	manifest.version = version;
	writeFileSync(manifestPath, `${JSON.stringify(manifest, null, 2)}\n`);
};

const stampMetadata = ({ dir, peerDependencies }) => {
	const manifestPath = join(repoRoot, dir, "package.json");
	const manifest = JSON.parse(readFileSync(manifestPath, "utf8"));
	manifest.license = "MIT";
	manifest.publishConfig = { ...manifest.publishConfig, access: "public" };
	manifest.repository = { type: "git", url: repositoryUrl };
	if (Object.keys(peerDependencies).length > 0) {
		manifest.peerDependencies = { ...manifest.peerDependencies, ...peerDependencies };
	}
	writeFileSync(manifestPath, `${JSON.stringify(manifest, null, 2)}\n`);
};

const failures = [];
const summary = [];

for (const pkg of generated) {
	stampMetadata(pkg);
	const fresh = freshContentHash(pkg.dir);
	const latest = registryLatest(pkg.name);

	if (latest === null) {
		const version = "0.0.1";
		setVersion(pkg.dir, version);
		summary.push({ name: pkg.name, decision: `seed ${version} (not on registry)` });
		if (!dryRun) publish(pkg, version);
		else packCheck(pkg);
		continue;
	}

	const published = publishedContentHash(pkg.name, latest);
	if (published === fresh) {
		summary.push({ name: pkg.name, decision: `skip (identical to ${latest})` });
		continue;
	}

	const version = patchBump(latest);
	setVersion(pkg.dir, version);
	summary.push({ name: pkg.name, decision: `publish ${latest} -> ${version}` });
	if (!dryRun) publish(pkg, version);
	else packCheck(pkg);
}

function publish(pkg, version) {
	try {
		run("npm", ["publish", "--access", "public"], {
			cwd: join(repoRoot, pkg.dir),
			stdio: "inherit",
		});
		console.log(`published ${pkg.name}@${version}`);
	} catch (error) {
		failures.push({ name: pkg.name, version, error: error.message });
	}
}

function packCheck(pkg) {
	run("npm", ["pack", "--dry-run", "--loglevel=error"], {
		cwd: join(repoRoot, pkg.dir),
		stdio: "inherit",
	});
}

console.log(`\n${dryRun ? "Dry run" : "Publish"} decisions:`);
for (const { name, decision } of summary) console.log(`  ${name}: ${decision}`);

if (failures.length > 0) {
	console.error("\nPublish failures:");
	for (const f of failures) console.error(`  ${f.name}@${f.version}: ${f.error}`);
	process.exit(1);
}
